sql:
SELECT model_name 
FROM forecast_models
WHERE model_id = (
    SELECT model_id 
    FROM model_results
    WHERE forecast_accuracy = (
        SELECT MAX(forecast_accuracy) 
        FROM model_results
    )
);

SELECT mortality_rate
FROM daily_cases
WHERE epi_date = '2022-11-01' AND region_id = 1;

SELECT SUM(cases) 
FROM daily_cases 
WHERE epi_date BETWEEN '2022-05-01' AND '2022-05-31';

SELECT users.user_name
FROM users
WHERE users.user_id IN (SELECT case_reports.patient_id FROM case_reports);

SELECT disease_name 
FROM diseases 
WHERE incubation_period = (SELECT MAX(incubation_period) FROM diseases);

SELECT role_name 
FROM user_roles
WHERE permissions LIKE '%edit%';

external_knowledge:
- "linger" implies a longer incubation period;
- "typical waiting period" refers to the average incubation period of all diseases;
- "symptoms to appear" relate to the incubation period of a disease.

sql:
SELECT disease_name, description
FROM diseases
WHERE incubation_period > (SELECT AVG(incubation_period) FROM diseases);

SELECT COUNT(DISTINCT reporting_site_id) AS distinct_reporting_sites
FROM case_reports
WHERE disease_id = 1 AND epi_date BETWEEN DATE('now', '-30 days') AND DATE('now');
